package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Constructor;

class CSVFormatTest {

    @Test
    void testIsEscapeCharacterSetWhenEscapeCharacterIsNull() {
        CSVFormat format = CSVFormat.DEFAULT;
        // DEFAULT has escapeCharacter == null
        assertFalse(format.isEscapeCharacterSet());
    }

    @Test
    void testIsEscapeCharacterSetWhenEscapeCharacterIsSet() {
        CSVFormat format = CSVFormat.DEFAULT.withEscape('\\');
        assertTrue(format.isEscapeCharacterSet());
    }

    @Test
    void testIsEscapeCharacterSetWhenEscapeCharacterIsSetToNullCharacter() throws Exception {
        // Create a new CSVFormat instance using reflection with escapeCharacter set to null explicitly
        Class<?> quoteModeClass = null;
        for (Class<?> innerClass : CSVFormat.class.getDeclaredClasses()) {
            if ("QuoteMode".equals(innerClass.getSimpleName())) {
                quoteModeClass = innerClass;
                break;
            }
        }
        assertNotNull(quoteModeClass, "QuoteMode class not found");

        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class, Character.class, quoteModeClass,
                Character.class, Character.class,
                boolean.class, boolean.class, String.class,
                String.class, Object[].class, String[].class,
                boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);

        CSVFormat format = constructor.newInstance(
                CSVFormat.DEFAULT.getDelimiter(),
                CSVFormat.DEFAULT.getQuoteCharacter(),
                CSVFormat.DEFAULT.getQuoteMode(),
                CSVFormat.DEFAULT.getCommentMarker(),
                null, // escapeCharacter explicitly set to null
                CSVFormat.DEFAULT.getIgnoreSurroundingSpaces(),
                CSVFormat.DEFAULT.getIgnoreEmptyLines(),
                CSVFormat.DEFAULT.getRecordSeparator(),
                CSVFormat.DEFAULT.getNullString(),
                null,
                CSVFormat.DEFAULT.getHeader(),
                CSVFormat.DEFAULT.getSkipHeaderRecord(),
                CSVFormat.DEFAULT.getAllowMissingColumnNames(),
                CSVFormat.DEFAULT.getIgnoreHeaderCase()
        );

        assertFalse(format.isEscapeCharacterSet());
    }
}
